package main

import "fmt"

func verificarSaidas(sairam []int) map[int]bool {
	saidas := make(map[int]bool)

	for _, p := range sairam {
		saidas[p] = true
	}
	return saidas
}

func imprimir(fila []int, saiu map[int]bool) {
	for _, p := range fila {
		if !saiu[p] {
			fmt.Printf("%v", p)
		}
	}
}

func main() {
	var qtd, identificadorPessoas int
	fmt.Scan(&qtd)

	fila := make([]int, qtd)

	for i := 0; i < qtd; i++ {
		fmt.Scan(&fila[i])
	}

	fmt.Scan(&identificadorPessoas)
	sairam := make([]int, identificadorPessoas)

	for i := 0; i < identificadorPessoas; i++ {
		fmt.Scan(&sairam[i])
	}

	resultado := verificarSaidas(sairam)
	imprimir(fila, resultado)
}
